@page "/inventory"
@using InventoryApp.Services
@rendermode InteractiveServer
@attribute [StreamRendering]
@inject IEquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_equipment is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _equipment)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _equipment;
    private PersistingComponentStateSubscription _persistingSubscription;

    private const string PersistenceKey = "equipment-data";

    protected override async Task OnInitializedAsync()
    {
        _persistingSubscription = ApplicationState.RegisterOnPersisting(PersistState);

        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>(PersistenceKey, out var restored))
        {
            // Interactive render: reuse data persisted during SSR — no second fetch
            _equipment = restored;
        }
        else
        {
            // SSR (or first render with no persisted state): fetch from service
            _equipment = await EquipmentService.GetEquipmentAsync();
        }
    }

    private Task PersistState()
    {
        ApplicationState.PersistAsJson(PersistenceKey, _equipment);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistingSubscription.Dispose();
    }
}

